grid:




































































        select 'load$GridSalaryInformationDetail$(this);' as message
return




        select 'dispose$GridSalaryInformationDetail$(this);' as message
return







function load$GridSalaryInformationDetail$(g) {g.add_commandEvent(on$GridSalaryInformationDetail$ExecuteCommand);}
function dispose$GridSalaryInformationDetail$(g) {try {g.remove_commandEvent(on$GridSalaryInformationDetail$ExecuteCommand);} catch (ex) {}}
function on$GridSalaryInformationDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      break;
    case 'AfterInsertRow':
      if (g._rowCount == 1) {
        g._setItemValue(1, g._getColumnOrder('ma_ngach'), f.getItemValue('ma_ngach'));
        g._setItemValue(1, g._getColumnOrder('ma_bac'), f.getItemValue('ma_bac'));
        g._setItemValue(1, g._getColumnOrder('he_so_luong'), f.getItemValue('he_so_luong'));
        g._setItemValue(1, g._getColumnOrder('he_so_dc'), f.getItemValue('he_so_dc'));
        g._setItemValue(1, g._getColumnOrder('tien_khoan'), f.getItemValue('tien_khoan'));
      }
      break;
    default:
      break;
  }
}








select @@fieldExternal from @@prime$partition$current a left join hrdmnl b on a.ma_ngach = b.ma_ngach left join hrdmbl c on a.ma_bac = c.ma_bac where @@whereClause order by @@orderByClause





